class Solution:
    def sumDistance(self, nums, s, d):
        MOD = 10 ** 9 + 7
        n = len(nums)
        finals = [nums[i] + d if s[i] == 'R' else nums[i] - d for i in range(n)]
        total = 0
        for i in range(n):
            for j in range(i + 1, n):
                total += abs(finals[i] - finals[j])
        return total % MOD

