var sumDistance = function(nums, s, d) {
    const n = nums.length;
    const bd = BigInt(d);
    const finals = new Array(n);
    for (let i = 0; i < n; i++) {
        const base = BigInt(nums[i]);
        finals[i] = s[i] === 'R' ? base + bd : base - bd;
    }
    finals.sort((a, b) => (a < b ? -1 : a > b ? 1 : 0));
    let total = 0n;
    let prefix = 0n;
    for (let i = 0; i < n; i++) {
        total += BigInt(i) * finals[i] - prefix;
        prefix += finals[i];
    }
    const MOD = 1000000007n;
    let result = total % MOD;
    if (result < 0n) result += MOD;
    return Number(result);
};
